from flask import Flask, send_file, abort
from io import BytesIO

app = Flask(__name__)

INVOICES = {
    1: b"%PDF-1.4\n%Fake invoice 1 PDF content\n",
    2: b"%PDF-1.4\n%Fake invoice 2 PDF content\n",
    3: b"%PDF-1.4\n%Fake invoice 3 PDF content\n",
}

@app.route("/api/invoices/<int:invoice_id>/download", methods=["GET"])
def download_invoice(invoice_id):
    pdf_data = INVOICES.get(invoice_id)
    if pdf_data is None:
        abort(404)

    return send_file(
        BytesIO(pdf_data),
        mimetype="application/pdf",
        as_attachment=True,
        download_name=f"invoice_{invoice_id}.pdf",
    )

